from pathlib import Path
from typing import List, Optional, Collection, Mapping, Iterable

import numpy as np
from geosat.cloud import PointCloud, rasterization
from geosat.cloud.rasterization import Rasterizer

from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata
from geosat.psanp.abstractions.stage import Stage

_RASTER_FN_CHOICES = {
    "pixel_is_point": rasterization.RasterFunctionType.PixelIsPoint,
    "pixel_is_area": rasterization.RasterFunctionType.PixelIsArea,
    "pixel_is_global": rasterization.RasterFunctionType.PixelIsGlobal,
}
_VALUE_FN_CHOICES = {
    "max": rasterization.ValueFunctionType.Max,
    "min": rasterization.ValueFunctionType.Min,
    "accumulate": rasterization.ValueFunctionType.Accumulate,
}


def _raster_fn_str_to_enum(raster_fn: str) -> rasterization.RasterFunctionType:
    return _RASTER_FN_CHOICES[raster_fn]


def _value_fn_str_to_enum(value_fn: str) -> rasterization.ValueFunctionType:
    return _VALUE_FN_CHOICES[value_fn]


class NoFieldsException(ValueError):
    """An exception raised when trying to instantiate a ``GeoTiffWriter`` without providing any fields"""


class InconsistentTypeException(ValueError):
    """An exception raised when executing a ``GeoTiffWriter`` on fields with inconsistent data types"""


class GeoTiffWriter(Stage):
    """
    This stage creates a raster of the point cloud it receives
    and writes it as a GeoTiff.

    In the 'out_path' option, '$name' can be used as a placeholder that will
    be replaced by the input point cloud name

    e.g. if the input_cloud is "R1_0+000_0+050.laz"
    then ``"output_path": "$name"`` will give "R1_0+000_0+050"

    Example:

    .. code-block:: json

        {
          "stages": [
            {
              "name": "GeoTiffWriter",
              "out_path": "$name.tiff",
              "precision": 0.2,
              "value_function": "max",
              "fields": "red green blue",
              "classes": "ground smooth_ground"
            }
          ]
        }

    """

    def __init__(
        self,
        out_path: str = "$name.tiff",
        fields: Collection[str] = ("intensity",),
        precision: float = 0.2,
        value_function: rasterization.ValueFunctionType = rasterization.ValueFunctionType.Max,
        raster_function: rasterization.RasterFunctionType = rasterization.RasterFunctionType.PixelIsPoint,
        classes: Optional[Collection[str]] = None,
        stage_name: Optional[str] = None,
    ):
        super().__init__(stage_name)
        if len(fields) == 0:
            raise NoFieldsException("At least one field must be provided")
        self.out_path = out_path
        self.fields = fields
        self.precision = precision
        self.value_function = value_function
        self.raster_function = raster_function
        self.classes = classes

    def _filter_by_class_name(
        self, cloud: PointCloud, classification_codes: Mapping[str, int]
    ) -> PointCloud:
        if self.classes is None:
            return cloud
        class_identifiers = [
            classification_codes[class_name] for class_name in self.classes
        ]
        mask = np.isin(cloud.classification, class_identifiers)
        return cloud[mask]

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option(
                "out_path",
                type_cast=str,
                required=True,
                description="Where the GeoTiff will be written. The special variable '$name' "
                "is replaced by the input point cloud stem. For example, if 'out_path' is 'ORTHOS/ortho_$name.tiff', "
                "a point cloud at 'LAZ/001.laz' will generate a GeoTiff at 'ORTHOS/ortho_001.tiff'",
            ),
            Option(
                "fields",
                type_cast=lambda string: string.split(" "),
                required=True,
                description="The fields of the point cloud to project on the image. "
                "They must be separated by spaces. For example: 'intensity' or 'red green blue'",
            ),
            Option(
                "precision",
                type_cast=float,
                required=True,
                description="Size of the side of the pixels, in meters",
            ),
            Option(
                "value_function",
                type_cast=_value_fn_str_to_enum,
                required=True,
                description="Indicates which pixel value should be displayed. "
                f"Options: {list(_VALUE_FN_CHOICES)}",
            ),
            Option(
                "raster_function",
                type_cast=_raster_fn_str_to_enum,
                required=False,
                description="Describes how the raster is aligned relatively to the point cloud. "
                f"Options: {list(_RASTER_FN_CHOICES)}",
            ),
            Option(
                "classes",
                type_cast=lambda string: string.split(" "),
                required=False,
                description="Class names that should be included in the corresponding raster. "
                "Must be separated by spaces. By default all points are displayed. The "
                "class names must be defined in the classification codes of the pipeline.",
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        dtypes = {
            cloud.fields[field_name].dtype: field_name for field_name in self.fields
        }
        if len(dtypes) > 1:
            raise InconsistentTypeException(
                f"All fields must have the same data type. Found {dtypes}"
            )

        _cloud = self._filter_by_class_name(
            cloud, pipeline_metadata.classification_codes
        )
        rasterizer = Rasterizer.from_point_cloud(
            _cloud, self.precision, self.raster_function
        )
        img = rasterizer.create_raster(_cloud, list(self.fields), self.value_function)

        stem = Path(_cloud.metadata["filepath"]).stem
        out_path = self.out_path.replace("$name", stem)
        rasterizer.write_image_as_geotiff(
            img,
            out_path,
            spatial_reference_wkt=_cloud.metadata.get("srs_wkt", None),
            no_data=0,
        )
        return (cloud,)
